const transactionId = window.orderConfig?.transactionId;

// Setup API Endpoint
const API_BASE_URL = 'https://api.robertwp.com/api';

// App Configuration
const APP_CONFIG = {
    site_url: 'https://robertwp.com',
    plugin_name: 'RW PostViewStats Pro',
    plugin_slug: 'rw-postviewstats-pro',
    plugin_version: '1.0.0'
};

// API Configuration
const API_CONFIG = {
    getTransaction: `${API_BASE_URL}/paddle/transactions`,
    getCustomer: `${API_BASE_URL}/paddle/customers`,
    getWpSyncToken: `${API_BASE_URL}/auth/issue-wp-sync-token`,
    wpUserSync: `${APP_CONFIG.site_url}/wp-json/rw-user-sync/v1/get-or-create`,
    getOrderToken: `${API_BASE_URL}/auth/issue-order-token`,
    getDownloadUrl: `${API_BASE_URL}/wp/get-download-url`,
    getLicenseKey: `${API_BASE_URL}/wp/get-license-key`,
    getActivationUrl: `${API_BASE_URL}/wp/get-activation-url`,
    sendOrderEmail: `${API_BASE_URL}/wp/send-order-email`
};

class OrderCompletePage {
    constructor(transactionId) {
        this.transactionId = transactionId;
        this.customerEmail = null;
        this.userId = null;
        this.deliverables = {
            download: { status: 'pending', data: null },
            license: { status: 'pending', data: null },
            activation: { status: 'pending', data: null }
        };

        this.storageKey = `order_${this.transactionId}`;
        this.init();
    }

    getTransactionId() {
        const urlParams = new URLSearchParams(window.location.search);
        return urlParams.get('transaction_id');
    }

    async init() {
        if (!this.transactionId) {
            this.showError('Invalid Transaction ID');
            return;
        }

        // Check whether the order has been processed.
        const cachedData = this.getCachedData();
        if (cachedData && cachedData.completed) {
            // 隐藏加载状态，显示app
            document.getElementById('initial-loading').style.display = 'none';
            document.getElementById('app').style.display = 'block';
            this.renderCompletedPage(cachedData);
            return;
        }

        // 显示主内容，隐藏加载状态
        document.getElementById('initial-loading').style.display = 'none';
        document.getElementById('app').style.display = 'block';

        // Show initial page
        this.renderInitialPage();

        // Start processing orders
        await this.processOrder();
    }

    getCachedData() {
        try {
            const cached = sessionStorage.getItem(this.storageKey);
            return cached ? JSON.parse(cached) : null;
        } catch (e) {
            return null;
        }
    }

    cacheData(data) {
        try {
            sessionStorage.setItem(this.storageKey, JSON.stringify(data));
        } catch (e) {
            console.error('Cache failure:', e);
        }
    }

    renderInitialPage() {
        const app = document.getElementById('app');
        app.innerHTML = `
                <div>
                    <span class="status-badge status-success">✓ Payment Successful</span>
                    <h1 id="mainTitle">Thank You for Your Purchase!</h1>

                    <div class="transaction-id">Transaction ID: ${this.transactionId}</div>

                    <div id="statusMessage" class="status-message info">
                        <p id="mainMessage">We're preparing your plugin and license information...</p>
                        <p id="subMessage" class="muted">This usually takes just a few seconds. Please don't close this page.</p>
                    </div>

                    <div class="progress-container">
                        <div class="progress-bar">
                            <div class="progress-fill" id="progressFill" style="width: 25%"></div>
                        </div>
                        <div class="progress-text" id="progressText">
                            Verifying payment information...
                        </div>
                    </div>

                    <div class="delivery-item generating" id="step1">
                        <div class="item-header">
                            <h3 class="item-title">1. Verifying Payment</h3>
                            <span class="item-status generating">In Progress</span>
                        </div>
                        <p>Retrieving your transaction information from Paddle...</p>
                    </div>

                    <div class="delivery-item generating" id="step2" style="opacity: 0.5;">
                        <div class="item-header">
                            <h3 class="item-title">2. Preparing Download</h3>
                            <span class="item-status">Pending</span>
                        </div>
                    </div>

                    <div class="delivery-item generating" id="step3" style="opacity: 0.5;">
                        <div class="item-header">
                            <h3 class="item-title">3. Generating License Key</h3>
                            <span class="item-status">Pending</span>
                        </div>
                    </div>

                    <div class="delivery-item generating" id="step4" style="opacity: 0.5;">
                        <div class="item-header">
                            <h3 class="item-title">4. Creating Activation Link</h3>
                            <span class="item-status">Pending</span>
                        </div>
                    </div>

                    <p class="muted">All resources will also be sent to your email once ready.</p>
                </div>
            `;
    }

    async processOrder() {
        try {
            // Step 1: Get Paddle transaction information
            this.updateStep('step1', 'In Progress', 'Retrieving transaction from Paddle...');
            await this.fetchPaddleData();

            // Step 2: Sync / Create WordPress user
            this.updateProgress(40, 'Syncing user information...');
            this.updateStep('step1', 'Complete', 'Payment verified successfully', true);
            this.updateStep('step2', 'In Progress', 'Preparing download link...', false, true);

            await this.syncUser();

            // Fetch first two deliverables in parallel to speed up
            this.updateProgress(60, 'Generating license information...');
            this.updateStep('step2', 'Complete', 'Download link ready', true);

            await Promise.all([
                this.generateDownloadUrl(),
                this.generateLicenseKey()
            ]);

            // Step 4: Generate account activation link
            this.updateProgress(80, 'Creating account activation link...');
            this.updateStep('step3', 'Complete', 'License key generated successfully', true);
            this.updateStep('step4', 'In Progress', 'Creating account activation link...', false, true);

            await this.generateActivationUrl();

            // All steps completed
            this.updateProgress(100, 'Order processing completed!');
            this.updateStep('step4', 'Complete', 'Account activation link created', true);

            // Update status message to show all ready
            this.updateStatusMessage('allReady');

            // Cache completed data
            const completedData = {
                completed: true,
                transactionId: this.transactionId,
                customerEmail: this.customerEmail,
                deliverables: this.deliverables,
                timestamp: Date.now()
            };
            this.cacheData(completedData);

            // Render final page (using email template styling)
            this.renderCompletedPage(completedData);

            // Trigger sending email (asynchronous background process, does not block UI)
            this.triggerEmailNotification();

        } catch (error) {
            console.error('Order processing failed:', error);

            // Update status message to show error but keep payment success
            this.updateStatusMessage('partialFailure', error.message);

            // Show support option
            this.showSupportOption(error.message);
        }
    }

    updateStatusMessage(type, errorMessage = '') {
        const mainTitle = document.getElementById('mainTitle');
        const mainMessage = document.getElementById('mainMessage');
        const subMessage = document.getElementById('subMessage');
        const statusMessage = document.getElementById('statusMessage');

        if (!mainTitle || !mainMessage || !subMessage || !statusMessage) return;

        // Check deliverables status
        const deliverables = [
            this.deliverables.download,
            this.deliverables.license,
            this.deliverables.activation
        ];

        const allReady = deliverables.every(d => d.status === 'ready');
        const anyFailed = deliverables.some(d => d.status === 'failed');
        const anyReady = deliverables.some(d => d.status === 'ready');

        if (allReady || type === 'allReady') {
            // All ready
            mainTitle.textContent = 'Thank You for Your Purchase!';
            mainMessage.textContent = 'All your plugin resources are ready.';
            subMessage.textContent = "We've also sent these details to your email.";
            statusMessage.className = 'status-message success';

        } else if (anyFailed || type === 'partialFailure') {
            // Some failed
            mainTitle.textContent = 'Payment Successful - Resources Pending';
            mainMessage.textContent = 'Your payment is confirmed, but some resources are still being prepared.';
            subMessage.textContent = "Don't worry - we're working on it. You can refresh the page or check your email in a few minutes.";
            statusMessage.className = 'status-message warning';

        } else if (anyReady) {
            // Some ready, some still processing
            mainMessage.textContent = 'Some resources are ready, others are still being prepared.';
            subMessage.textContent = 'Available items are shown below - the rest will appear automatically.';
            statusMessage.className = 'status-message info';

        } else {
            // All processing
            mainMessage.textContent = "We're preparing your plugin and license information...";
            subMessage.textContent = "This usually takes just a few seconds. Please don't close this page.";
            statusMessage.className = 'status-message info';
        }
    }

    showSupportOption(errorMessage = '') {
        const container = document.getElementById('app');

        // Check if support message already exists
        if (document.getElementById('supportMessage')) return;

        const supportDiv = document.createElement('div');
        supportDiv.id = 'supportMessage';
        supportDiv.className = 'support-message';
        supportDiv.innerHTML = `
                <p style="margin: 0; color: #856404;">
                    <strong>⚠️ Need help?</strong> If resources don't appear within 10 minutes,
                    <a href="mailto:support@robertwp.com?subject=Missing%20resources%20for%20transaction%20${this.transactionId}&body=Transaction%20ID:%20${this.transactionId}%0AError:%20${encodeURIComponent(errorMessage)}"
                       style="color: #856404; font-weight: bold;">
                        contact support
                    </a>
                    and mention transaction ID: <strong>${this.transactionId}</strong>
                </p>
            `;

        // Insert after status message
        const statusMessage = document.getElementById('statusMessage');
        if (statusMessage && statusMessage.nextSibling) {
            container.insertBefore(supportDiv, statusMessage.nextSibling);
        } else {
            container.appendChild(supportDiv);
        }
    }

    async fetchPaddleData() {
        try {
            const transactionResponse = await fetch(`${API_CONFIG.getTransaction}/${this.transactionId}`);

            if (!transactionResponse.ok) {
                const errorData = await transactionResponse.json();
                throw new Error(`Transaction query failed: ${transactionResponse.status} - ${errorData.error || 'Unknown error'}`);
            }

            const transactionData = await transactionResponse.json();

            // Extract customer_id - adjust according to the actual return structure of Paddle API
            const customerId = transactionData.data?.customer_id || transactionData.customer_id;

            if (!customerId) {
                throw new Error('Unable to get customer_id from customer response');
            }

            // Call your backend to get customer information
            const customerResponse = await fetch(`${API_CONFIG.getCustomer}/${customerId}`);

            if (!customerResponse.ok) {
                const errorData = await customerResponse.json();
                throw new Error(`Customer query failed: ${customerResponse.status} - ${errorData.error || 'Unknown error'}`);
            }

            const customerData = await customerResponse.json();

            // Extract email
            this.customerEmail = customerData.data?.email || customerData.email;

            if (!this.customerEmail) {
                throw new Error('Unable to get email from customer response');
            }

            // Update step display
            this.updateStep('step1', 'Complete', 'Payment verified successfully', true);
            this.updateStatusMessage();

        } catch (error) {
            // Mark step as failed
            this.updateStep('step1', 'Failed', 'Payment verification failed', false);
            this.deliverables.activation.status = 'failed';
            throw new Error(`支付信息验证失败: ${error.message}`);
        }
    }

    async syncUser() {
        try {
            // Step 1: Get sync token
            const tokenResponse = await fetch(`${API_CONFIG.getWpSyncToken}`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    site_url: APP_CONFIG.site_url
                })
            });

            if (!tokenResponse.ok) {
                const errorData = await tokenResponse.json().catch(() => ({}));
                throw new Error(`Failed to get sync token: ${tokenResponse.status} - ${errorData.message || 'Unknown error'}`);
            }

            const tokenData = await tokenResponse.json();
            const syncToken = tokenData.data.token;  // 假设返回的格式是 { token: "xxx" }

            if (!syncToken) {
                throw new Error('Sync token returned in incorrect format');
            }

            // Step 2: Sync user with token
            const response = await fetch(API_CONFIG.wpUserSync, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${syncToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    email: this.customerEmail
                })
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(`用户同步失败: ${response.status} - ${errorData.message || 'Unknown error'}`);
            }

            const data = await response.json();

            // Extract user_id based on actual return format
            this.userId = data.data.user_id;

            if (!this.userId) {
                throw new Error('用户同步返回格式错误：缺少user_id');
            }

            // Update progress display
            this.updateStep('step2', 'Complete', 'User sync successful', true);
            this.updateStatusMessage();

        } catch (error) {
            this.updateStep('step2', 'Failed', 'User sync failed', false);
            this.deliverables.activation.status = 'failed';
            throw new Error(`User sync failed: ${error.message}`);
        }
    }

    async generateDownloadUrl() {//TODO token
        try {
            const response = await fetch(API_CONFIG.getDownloadUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    user_id: this.userId,
                    slug: APP_CONFIG.plugin_slug,
                    version: APP_CONFIG.plugin_version
                })
            });

            if (!response.ok) {
                throw new Error('Failed to generate download link');
            }

            const data = await response.json();
            this.deliverables.download = {
                status: 'ready',
                data: {
                    url: data.url,
                }
            };

            this.updateStatusMessage();

        } catch (error) {
            console.error('Generate download URL failed:', error);
            this.deliverables.download = {
                status: 'failed',
                data: null
            };
            this.updateStatusMessage();
            throw error;
        }
    }

    async generateLicenseKey() {//TODO token
        try {
            const response = await fetch(API_CONFIG.getLicenseKey, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    slug: APP_CONFIG.plugin_slug
                })
            });

            if (!response.ok) {
                throw new Error('Failed to generate license key');
            }

            const data = await response.json();
            this.deliverables.license = {
                status: 'ready',
                data: {
                    key: data.key
                }
            };

            this.updateStatusMessage();

        } catch (error) {
            console.error('Generate license key failed:', error);
            this.deliverables.license = {
                status: 'failed',
                data: null
            };
            this.updateStatusMessage();
            throw error;
        }
    }

    async generateActivationUrl() {//TODO token
        try {
            const response = await fetch(API_CONFIG.getActivationUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    transaction_id: this.transactionId,
                    user_id: this.userId
                })
            });

            if (!response.ok) {
                throw new Error('Failed to generate activation link');
            }

            const data = await response.json();
            this.deliverables.activation = {
                status: 'ready',
                data: {
                    url: data.url,
                }
            };

            this.updateStatusMessage();

        } catch (error) {
            console.error('Generate activation URL failed:', error);
            this.deliverables.activation = {
                status: 'failed',
                data: null
            };
            this.updateStatusMessage();
            throw error;
        }
    }

    triggerEmailNotification() {//TODO token
        // Trigger backend API to send email, do not wait for response
        fetch(API_CONFIG.sendOrderEmail, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                transaction_id: this.transactionId,
                email: this.customerEmail
            }),
            keepalive: true
        }).catch(error => {
            console.error('Failed to trigger email notification:', error);
        });
    }

    updateStep(stepId, status, message, completed = false, showSpinner = false) {
        const stepElement = document.getElementById(stepId);
        if (!stepElement) return;

        const statusSpan = stepElement.querySelector('.item-status');
        const itemHeader = stepElement.querySelector('.item-header');
        const description = stepElement.querySelector('p');

        if (statusSpan) {
            statusSpan.textContent = status;
            statusSpan.className = `item-status ${completed ? 'ready' : status === 'In Progress' ? 'generating' : status === 'Failed' ? 'failed' : ''}`;
        }

        if (description && message) {
            description.textContent = message;
        }

        if (completed) {
            stepElement.classList.remove('generating', 'failed');
            stepElement.classList.add('ready');
            stepElement.style.opacity = '1';

            if (itemHeader && !itemHeader.querySelector('.completion-mark')) {
                const mark = document.createElement('span');
                mark.className = 'completion-mark';
                mark.innerHTML = ' ✓';
                mark.style.color = '#28a745';
                mark.style.fontWeight = 'bold';
                itemHeader.appendChild(mark);
            }
        } else if (status === 'Failed') {
            stepElement.classList.remove('generating', 'ready');
            stepElement.classList.add('failed');
            stepElement.style.opacity = '1';
        } else if (showSpinner) {
            stepElement.style.opacity = '1';
        }
    }

    updateProgress(width, text) {
        const fill = document.getElementById('progressFill');
        const textEl = document.getElementById('progressText');

        if (fill) fill.style.width = width + '%';
        if (textEl) textEl.textContent = text;
    }

    renderCompletedPage(data) {
        const app = document.getElementById('app');
        const d = data.deliverables;

        app.innerHTML = `
                <div>
                    <span class="status-badge status-success">✓ Payment Successful</span>
                    <h1>Thank You for Purchasing Our Plugin!</h1>

                    <div class="transaction-id">Transaction ID: ${this.transactionId}</div>

                    <div class="status-message success">
                        <p>All your plugin resources are ready. We've also sent these details to your email.</p>
                    </div>

                    <!-- Download Area -->
                    <div class="delivery-item ready">
                        <div class="item-header">
                            <h3 class="item-title">① Download the Plugin Now</h3>
                            <span class="item-status ready">Ready</span>
                        </div>

                        <p>Please download the plugin installation package (ZIP file) first, then install it in your WordPress admin panel:</p>

                        <a class="button" href="${d.download.data.url}" download="${d.download.data.url}">
                            Download Plugin Now
                        </a>

                        <p class="muted">
                            If the button does not work, copy and paste the following link into your browser:<br>
                            <a href="${d.download.data.url}">${d.download.data.url}</a>
                        </p>
                    </div>

                    <!-- License Key Area -->
                    <div class="delivery-item ready">
                        <div class="item-header">
                            <h3 class="item-title">② Your License Key</h3>
                            <span class="item-status ready">Ready</span>
                        </div>

                        <p>After installing the plugin, use the following License Key to activate the Pro features:</p>

                        <div style="display: flex; align-items: center;">
                            <span class="license-key" id="licenseKeyDisplay">${d.license.data.key}</span>
                            <button class="copy-button" onclick="copyToClipboard('${d.license.data.key}')">Copy</button>
                        </div>

                        <h3 class="item-title">③ Activation Steps</h3>
                        <ol>
                            <li>Install and activate the plugin from your WordPress admin panel.</li>
                            <li>Go to the plugin settings page and locate the License activation option.</li>
                            <li>Enter the License Key provided above and click "Activate".</li>
                        </ol>
                    </div>

                    <!-- Account Activation Area -->
                    <div class="delivery-item ready">
                        <div class="item-header">
                            <h3 class="item-title">④ Account Activation</h3>
                            <span class="item-status ready">Ready</span>
                        </div>

                        <p><strong>We have created an account for you on our official website.</strong></p>

                        <p>You can set your login password by clicking the button below (link valid for 24 hours):</p>

                        <a class="button" href="${d.activation.data.url}" target="_blank">
                            Set Account Password
                        </a>

                        <p class="muted">If you did not make this purchase or do not need a website account, you can ignore this.</p>
                    </div>

                    <!-- Documentation and Help -->
                    <div style="margin: 30px 0; border-top: 1px solid #eee;"></div>

                    <p>If you encounter any issues during the download, installation, or activation process, please feel free to contact us:</p>

                    <p><a href="mailto:support@robertwp.com">support@robertwp.com</a></p>

                    <a class="button" href="https://docs.robertwp.com/plugins/${APP_CONFIG.plugin_slug}/en/#/" target="_blank">
                        View Plugin Documentation
                    </a>

                    <!-- Email Reminder -->
                    <div style="margin-top: 30px; padding: 15px; background-color: #e7f3ff; border-radius: 6px;">
                        <p style="margin: 0; color: #004085;">
                            <strong>📧 Email Sent</strong> - We have sent the above information to your email <strong>${this.customerEmail}</strong> for your future reference.
                        </p>
                    </div>

                </div>
            `;
    }

    showError(message) {
        const app = document.getElementById('app');
        app.innerHTML = `
                <div>
                    <span class="status-badge status-error">Payment Issue Detected</span>
                    <h1>We're Having Trouble Processing Your Order</h1>
                    <p>${message}</p>
                    <p>Don't worry - your payment was successful. We're working on it.</p>
                    <p>Please try refreshing the page, or contact support: <a href="mailto:support@robertwp.com">support@robertwp.com</a></p>
                    <button class="button" onclick="location.reload()">Refresh Page</button>
                </div>
            `;
    }

}

// Page initialization
document.addEventListener('DOMContentLoaded', () => {
    if (!transactionId) {
        document.getElementById('app').innerHTML = `
            <div class="error-message">
                <h2>Invalid Transaction ID</h2>
                <p>Please contact support: <a href="mailto:support@robertwp.com">support@robertwp.com</a></p>
            </div>
        `;
        return;
    }

    new OrderCompletePage(transactionId);
});

// Global function for copy functionality
window.copyToClipboard = function(text, buttonElement) {
    navigator.clipboard.writeText(text).then(() => {
        const originalText = buttonElement.textContent;
        buttonElement.textContent = 'Copied!';
        buttonElement.classList.add('success');

        setTimeout(() => {
            buttonElement.textContent = originalText;
            buttonElement.classList.remove('success');
        }, 2000);
    }).catch(() => {
        const textarea = document.createElement('textarea');
        textarea.value = text;
        document.body.appendChild(textarea);
        textarea.select();
        document.execCommand('copy');
        document.body.removeChild(textarea);

        const originalText = buttonElement.textContent;
        buttonElement.textContent = 'Copied!';
        buttonElement.classList.add('success');
        setTimeout(() => {
            buttonElement.textContent = originalText;
            buttonElement.classList.remove('success');
        }, 2000);
    });
};